import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

import { prisma } from "@rlm-saas/database";

import { requireAuth } from "@/lib/auth";
import { handleError, successResponse } from "@/lib/api/responses";

// Query parameters validation schema
const getUsersQuerySchema = z.object({
  limit: z
    .string()
    .optional()
    .transform((val) => (val ? parseInt(val, 10) : 50))
    .refine((val) => val > 0 && val <= 100, {
      message: "Limit must be between 1 and 100",
    }),
  offset: z
    .string()
    .optional()
    .transform((val) => (val ? parseInt(val, 10) : 0))
    .refine((val) => val >= 0, {
      message: "Offset must be non-negative",
    }),
  search: z.string().optional(),
  status: z.enum(["active", "inactive", "banned"]).optional(),
  teamId: z.string().optional(),
});

type GetUsersQuery = z.infer<typeof getUsersQuerySchema>;

export async function GET(request: NextRequest): Promise<NextResponse> {
  try {
    // Authentication
    const user = await requireAuth();

    // Parse and validate query parameters
    const url = new URL(request.url);
    const queryParams = Object.fromEntries(url.searchParams.entries());
    const validatedQuery = getUsersQuerySchema.parse(queryParams);

    // Delegate to query function
    const result = await getUsersList(validatedQuery, user.id);

    return successResponse(result);
  } catch (error) {
    return handleError(error);
  }
}

// Database query function (should be in lib/db/queries/users.ts)
async function getUsersList(
  query: GetUsersQuery,
  requesterId: string
): Promise<{
  users: Array<{
    id: string;
    name: string | null;
    email: string;
    image: string | null;
    status: string;
    createdAt: Date;
    updatedAt: Date;
  }>;
  total: number;
  hasMore: boolean;
}> {
  const { limit, offset, search, status, teamId } = query;

  // Build where clause
  const where: any = {};

  if (search) {
    where.OR = [
      { name: { contains: search, mode: "insensitive" } },
      { email: { contains: search, mode: "insensitive" } },
    ];
  }

  if (status) {
    where.status = status.toUpperCase();
  }

  if (teamId) {
    where.teamMembers = {
      some: {
        teamId: teamId,
      },
    };
  }

  // Execute queries in parallel
  const [users, total] = await Promise.all([
    prisma.user.findMany({
      where,
      select: {
        id: true,
        name: true,
        email: true,
        image: true,
        status: true,
        createdAt: true,
        updatedAt: true,
      },
      orderBy: { createdAt: "desc" },
      take: limit,
      skip: offset,
    }),
    prisma.user.count({ where }),
  ]);

  return {
    users,
    total,
    hasMore: offset + limit < total,
  };
}
```

