import { calculatePrice } from "@/lib/utils/pricing";

describe("calculatePrice", () => {
  it("should calculate correct price for positive values", () => {
    const result = calculatePrice(3, 10.50);
    expect(result).toBe(31.50);
  });

  it("should handle zero quantity", () => {
    const result = calculatePrice(0, 15.99);
    expect(result).toBe(0);
  });

  it("should handle zero unit price", () => {
    const result = calculatePrice(5, 0);
    expect(result).toBe(0);
  });

  it("should handle decimal quantities", () => {
    const result = calculatePrice(2.5, 8.00);
    expect(result).toBe(20.00);
  });

  it("should handle large numbers", () => {
    const result = calculatePrice(1000, 999.99);
    expect(result).toBe(999990);
  });

  it("should handle floating point precision correctly", () => {
    const result = calculatePrice(3, 0.1);
    // Use toBeCloseTo for floating point comparisons
    expect(result).toBeCloseTo(0.3, 2);
  });
});
```

