 * Calculates the total price based on quantity and unit price
 * @param quantity - The number of items
 * @param unitPrice - The price per item
 * @returns The total price (quantity * unitPrice)
 */
export function calculatePrice(quantity: number, unitPrice: number): number {
  if (quantity < 0 || unitPrice < 0) {
    throw new Error("Quantity and unit price must be non-negative");
  }

  return quantity * unitPrice;
}
